<?php require_once __DIR__.'/../includes/auth_check.php';$title='Réservations';include __DIR__.'/../includes/admin_header.php';$where='';$p=[];if(trim($_GET['status']??'')!==''){$where='WHERE l.status=:s';$p['s']=$_GET['status'];}$st=$pdo->prepare("SELECT l.*,c.name car_name FROM leads l JOIN cars c ON c.id=l.car_id $where ORDER BY l.created_at DESC");$st->execute($p);?><h1>Demandes de réservation</h1><form class="filters"><select name="status"><option value="">Tous statuts</option><option value="new">Nouvelle</option><option value="contacted">Contacté</option><option value="confirmed">Confirmée</option><option value="cancelled">Annulée</option></select><button class="btn primary">Filtrer</button></form><table><tr><th>Client</th><th>Téléphone</th><th>Voiture</th><th>Ville</th><th>Lieu</th><th>Dates</th><th>Statut</th><th>Créé</th></tr><?php foreach($st as $l):?><tr><td><?=e($l['full_name'])?></td><td><?=e($l['phone'])?></td><td><?=e($l['car_name'])?></td><td><?=e($l['pickup_city'])?></td><td><?=e($l['pickup_location'])?></td><td><?=e($l['pickup_date'])?> → <?=e($l['return_date'])?></td><td><form method="post" action="/admin/reservations/update.php"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($l['id'])?>"><select name="status"><option value="new">Nouvelle</option><option value="contacted">Contacté</option><option value="confirmed">Confirmée</option><option value="cancelled">Annulée</option></select><button>OK</button></form></td><td><?=e($l['created_at'])?></td></tr><?php endforeach;?></table><?php include __DIR__.'/../includes/admin_footer.php';?>